export function update(entity, dt, world) {
  if (!entity.state) {
    entity.state = { timer: 0, lastX: entity.transform.x };
  }
  entity.state.timer += dt;
  let dx = entity.transform.x - entity.state.lastX;
  let dir = dx > 0 ? 1 : (dx < 0 ? -1 : 1);
  entity.state.lastX = entity.transform.x;

  if (entity.state.timer > 2.0) {
    entity.state.timer = 0;
    let proj = null;
    if (world && world.entities) {
      proj = world.entities.find(e => e.name === 'BossProjectile');
    }
    if (proj && proj.rigidBody) {
      proj.transform.x = entity.transform.x + dir * 50;
      proj.transform.y = entity.transform.y;
      proj.rigidBody.velocity = { x: dir * 400, y: 0 };
    }
  }
}

export function update(entity, dt) {
  if (entity.rigidBody) {
    entity.rigidBody.velocity.y = 0;
  }
  if (entity.transform.x < 0 || entity.transform.x > 2500) {
    entity.transform.x = -1000;
    entity.transform.y = -1000;
    if(entity.rigidBody) entity.rigidBody.velocity.x = 0;
  }
}

